   377→  };
   378→  ai_routing: {
   379→    high_confidence_threshold: number;
   380→    ai_required_threshold: number;
   381→    skip_ai_conditions: string[];
   382→  };
   383→}
   384→
   385→interface CategorySignals {
   386→  hard_assertions: {
   387→    from_domains_ref?: {
   388→      source_group: string;
   389→      confidence: string;
   390→    };
   391→    subject_prefixes?: string[];
   392→    from_addresses?: string[];
   393→  };
   394→  strong_indicators: {
   395→    from_domains_ref?: {
   396→      source_group: string;
   397→      confidence: string;
   398→    };
   399→    subject_contains?: string[];
   400→    body_contains?: string[];
   401→  };
   402→  disambiguators?: {
   403→    boost_if_present_attributes?: string[];
   404→    suppress_if_body_contains?: string[];
   405→    boost_if_absent_categories?: string[];
