    system_prompt: string[];
    user_prompt: string[];
  };
}

interface JSONSchema {
  type: string;
  properties: Record<string, any>;
  required: string[];
}

interface CompiledRule {
  category: string;
  subtype: string;
  tier: string;
  pattern: RegExp;
