  describe('Operation Strategy Pattern', () => {
    describe('ContainsAnyStrategy', () => {
      it('compiles containsAny rules with case-insensitive matching', () => {
        const baseProcessing = validMinimalCategoryConfig.processingConfig;
        const config = createTestCategoryConfig({
          processingConfig: {
            ...baseProcessing,
            topLevelCategories: {
              test: {
                description: 'Test category',
                subtypes: {
                  basic: {
                    description: 'Basic test',
                    derived: false,
                    parallelSafe: true,
                    ruleBasedClassification: {
                      highConfidence: [
                        {
                          field: 'subject',
                          operation: 'containsAny',
                          values: ['Receipt', 'Invoice'],
                          weight: 1.0,
                        },
                      ],
                    },
                  },
                },
                aiFinalClassification: {
                  categoryDescription: 'Test',
                  decisionCriteria: ['Test criteria'],
                },
              },
            },
          },
        });

        const compiled = compiler.compileRules(config);
        expect(compiled).toHaveLength(1);
        expect(compiled[0].pattern).toBeDefined();
        expect(compiled[0].pattern?.test('Your receipt is ready')).toBe(true);
        expect(compiled[0].pattern?.test('Invoice available')).toBe(true);
        expect(compiled[0].pattern?.test('Payment processed')).toBe(false);
      });

      it('escapes special regex characters in containsAny values', () => {
        const baseProcessing = validMinimalCategoryConfig.processingConfig;
        const config = createTestCategoryConfig({
          processingConfig: {
            ...baseProcessing,
            topLevelCategories: {
              test: {
                description: 'Test category',
                subtypes: {
                  basic: {
                    description: 'Basic test',
                    derived: false,
                    parallelSafe: true,
                    ruleBasedClassification: {
                      highConfidence: [
                        {
                          field: 'subject',
                          operation: 'containsAny',
                          values: ['$100.00', 'Price: $50'],
                          weight: 1.0,
                        },
                      ],
                    },
                  },
                },
                aiFinalClassification: {
                  categoryDescription: 'Test',
                  decisionCriteria: ['Test criteria'],
                },
              },
            },
          },
        });

        const compiled = compiler.compileRules(config);
        expect(compiled).toHaveLength(1);
        expect(compiled[0].pattern?.test('Total: $100.00')).toBe(true);
        expect(compiled[0].pattern?.test('Price: $50')).toBe(true);
        // Should NOT match if not escaped ($ is regex special char)
        expect(compiled[0].pattern?.test('X100X00')).toBe(false);
      });
    });

    describe('StartsWithStrategy', () => {
      it('compiles startsWith rules with anchor at beginning', () => {
        const baseProcessing = validMinimalCategoryConfig.processingConfig;
        const config = createTestCategoryConfig({
          processingConfig: {
            ...baseProcessing,
            topLevelCategories: {
