import { RuleCompiler } from '../../../src/config/rule-compiler';
import {
  createTestCategoryConfig,
  validMinimalCategoryConfig,
} from '../../fixtures/configs/valid-minimal-category-config';

describe('RuleCompiler', () => {
  const compiler = new RuleCompiler();

  it('compiles literal rule operations into case-insensitive regular expressions', () => {
    const baseProcessing = validMinimalCategoryConfig.processingConfig;
    const configWithRules = createTestCategoryConfig({
      processingConfig: {
        ...baseProcessing,
        topLevelCategories: {
          financial: {
            description: 'Financial communications',
            subtypes: {
              receipt: {
                description: 'Receipts',
                derived: false,
                parallelSafe: true,
                ruleBasedClassification: {
                  highConfidence: [
                    {
                      field: 'subject',
                      operation: 'containsAny',
                      values: ['Receipt #', 'Invoice (Final)'],
                      weight: 1,
                    },
                    {
                      field: 'subject',
                      operation: 'startsWith',
                      values: ['Payment confirmation'],
                      weight: 0.8,
                    },
                    {
                      field: 'subject',
                      operation: 'endsWith',
                      values: ['statement.pdf'],
                      weight: 0.6,
                    },
                  ],
                  mediumConfidence: [
                    {
                      field: 'body',
                      operation: 'regexAny',
                      values: ['total\\s+\\$\\d+\\.\\d{2}'],
                      weight: 0.5,
                    },
                  ],
                },
              },
            },
            aiFinalClassification: {
              categoryDescription: 'Financial classification',
              decisionCriteria: ['Contains transaction details'],
            },
          },
        },
      },
    });

    const compiled = compiler.compileRules(configWithRules);

    expect(compiled).toHaveLength(4);
    const ids = compiled.map((rule) => rule.id);
    expect(ids).toContain('financial.receipt.highConfidence.0');
    expect(ids).toContain('financial.receipt.highConfidence.1');
    expect(ids).toContain('financial.receipt.highConfidence.2');
    expect(ids).toContain('financial.receipt.mediumConfidence.0');

    const containsAnyRule = compiled.find((rule) => rule.id.endsWith('0'));
    expect(containsAnyRule).toBeDefined();
    if (containsAnyRule && containsAnyRule.pattern) {
      expect(containsAnyRule.pattern.test('Your Receipt #12345 is ready')).toBe(true);
      expect(containsAnyRule.pattern.test('Invoice (Final) available')).toBe(true);
      expect(containsAnyRule.pattern.test('Invoice [Draft]')).toBe(false);
    }
  });

  it('skips invalid regex patterns without throwing', () => {
    const baseProcessing = validMinimalCategoryConfig.processingConfig;
    const configWithInvalidRegex = createTestCategoryConfig({
      processingConfig: {
        ...baseProcessing,
        topLevelCategories: {
          alerts: {
            description: 'Alert notifications',
            subtypes: {
              generic: {
                description: 'Generic alert',
                derived: false,
                parallelSafe: true,
                ruleBasedClassification: {
                  highConfidence: [
                    {
                      field: 'subject',
                      operation: 'regexAny',
                      values: ['(*invalid'],
                      weight: 1,
                    },
                  ],
                },
              },
            },
            aiFinalClassification: {
              categoryDescription: 'Alert notifications',
              decisionCriteria: ['Contains alert keywords'],
            },
          },
        },
      },
    });

    expect(() => compiler.compileRules(configWithInvalidRegex)).not.toThrow();
    const compiled = compiler.compileRules(configWithInvalidRegex);
    expect(compiled).toHaveLength(0);
  });

  it('compiles notContains rules for exclusion patterns', () => {
    const baseProcessing = validMinimalCategoryConfig.processingConfig;
    const configWithNotContains = createTestCategoryConfig({
      processingConfig: {
        ...baseProcessing,
        topLevelCategories: {
          subscriptionContent: {
            description: 'Subscription content',
            subtypes: {
              newsletter: {
                description: 'Newsletters',
                derived: false,
                parallelSafe: true,
                ruleBasedClassification: {
                  highConfidence: [
                    {
                      field: 'subject',
                      operation: 'notContains',
                      values: ['unsubscribe', 'spam', 'advertisement'],
                      weight: 0.5,
                    },
                  ],
                },
              },
            },
            aiFinalClassification: {
              categoryDescription: 'Subscription content',
              decisionCriteria: ['Newsletter-like content'],
            },
          },
        },
      },
    });

    const compiled = compiler.compileRules(configWithNotContains);
    expect(compiled).toHaveLength(1);
    expect(compiled[0].id).toBe('subscriptionContent.newsletter.highConfidence.0');
  });
});

