                    description: 'Basic test',
                    derived: false,
                    parallelSafe: true,
                    ruleBasedClassification: {
                      highConfidence: [
                        {
                          field: 'subject',
                          operation: 'startsWith',
                          values: ['RE:', 'FWD:'],
                          weight: 1.0,
                        },
                      ],
                    },
                  },
                },
                aiFinalClassification: {
                  categoryDescription: 'Test',
                  decisionCriteria: ['Test criteria'],
                },
              },
            },
          },
        });

        const compiled = compiler.compileRules(config);
        expect(compiled).toHaveLength(1);
        expect(compiled[0].pattern?.test('RE: Your email')).toBe(true);
        expect(compiled[0].pattern?.test('FWD: Important')).toBe(true);
        expect(compiled[0].pattern?.test('Check this RE: stuff')).toBe(false);
      });
    });

    describe('EndsWithStrategy', () => {
      it('compiles endsWith rules with anchor at end', () => {
        const baseProcessing = validMinimalCategoryConfig.processingConfig;
        const config = createTestCategoryConfig({
          processingConfig: {
            ...baseProcessing,
            topLevelCategories: {
              test: {
                description: 'Test category',
                subtypes: {
                  basic: {
                    description: 'Basic test',
                    derived: false,
                    parallelSafe: true,
                    ruleBasedClassification: {
                      highConfidence: [
                        {
                          field: 'subject',
                          operation: 'endsWith',
                          values: ['.pdf', '.docx'],
                          weight: 1.0,
                        },
                      ],
                    },
                  },
                },
                aiFinalClassification: {
                  categoryDescription: 'Test',
                  decisionCriteria: ['Test criteria'],
                },
              },
            },
          },
        });

        const compiled = compiler.compileRules(config);
        expect(compiled).toHaveLength(1);
        expect(compiled[0].pattern?.test('document.pdf')).toBe(true);
        expect(compiled[0].pattern?.test('report.docx')).toBe(true);
        expect(compiled[0].pattern?.test('file.pdf.backup')).toBe(false);
      });
    });

    describe('RegexAnyStrategy', () => {
      it('compiles regexAny rules with raw regex patterns', () => {
        const baseProcessing = validMinimalCategoryConfig.processingConfig;
        const config = createTestCategoryConfig({
          processingConfig: {
            ...baseProcessing,
            topLevelCategories: {
              test: {
                description: 'Test category',
                subtypes: {
                  basic: {
                    description: 'Basic test',
                    derived: false,
                    parallelSafe: true,
                    ruleBasedClassification: {
                      highConfidence: [
                        {
                          field: 'body',
                          operation: 'regexAny',
                          values: ['\\$\\d+\\.\\d{2}', 'total.*amount'],
                          weight: 1.0,
                        },
                      ],
                    },
                  },
                },
                aiFinalClassification: {
                  categoryDescription: 'Test',
                  decisionCriteria: ['Test criteria'],
                },
              },
            },
          },
        });

        const compiled = compiler.compileRules(config);
        expect(compiled).toHaveLength(1);
        expect(compiled[0].pattern?.test('Price: $99.99')).toBe(true);
        expect(compiled[0].pattern?.test('Total due amount: $50')).toBe(true);
        expect(compiled[0].pattern?.test('No match here')).toBe(false);
      });
    });

    describe('NotContainsStrategy', () => {
      it('compiles notContains rules without RegExp pattern', () => {
        const baseProcessing = validMinimalCategoryConfig.processingConfig;
        const config = createTestCategoryConfig({
          processingConfig: {
            ...baseProcessing,
            topLevelCategories: {
              test: {
                description: 'Test category',
                subtypes: {
                  basic: {
                    description: 'Basic test',
                    derived: false,
                    parallelSafe: true,
                    ruleBasedClassification: {
                      highConfidence: [
                        {
                          field: 'subject',
                          operation: 'notContains',
                          values: ['spam', 'unsubscribe'],
                          weight: 0.5,
                        },
                      ],
                    },
                  },
                },
                aiFinalClassification: {
                  categoryDescription: 'Test',
                  decisionCriteria: ['Test criteria'],
                },
              },
            },
          },
        });

        const compiled = compiler.compileRules(config);
        expect(compiled).toHaveLength(1);
        expect(compiled[0].pattern).toBeNull();
        expect(compiled[0].operation).toBe('notContains');
        expect(compiled[0].values).toEqual(['spam', 'unsubscribe']);
        expect(compiled[0].field).toBe('subject');
      });
    });

    it('handles unsupported operations gracefully', () => {
      const baseProcessing = validMinimalCategoryConfig.processingConfig;
      const config = createTestCategoryConfig({
        processingConfig: {
          ...baseProcessing,
          topLevelCategories: {
            test: {
              description: 'Test category',
              subtypes: {
                basic: {
                  description: 'Basic test',
                  derived: false,
                  parallelSafe: true,
                  ruleBasedClassification: {
                    highConfidence: [
                      {
                        field: 'subject',
                        // eslint-disable-next-line @typescript-eslint/no-explicit-any
                        operation: 'unknownOperation' as any, // Testing unsupported operation handling
                        values: ['test'],
                        weight: 1.0,
                      },
                    ],
                  },
                },
              },
              aiFinalClassification: {
                categoryDescription: 'Test',
                decisionCriteria: ['Test criteria'],
              },
            },
          },
        },
      });

      const compiled = compiler.compileRules(config);
      // Should skip unsupported operation
      expect(compiled).toHaveLength(0);
    });
  });
});

