     1→/**
     2→ * API types for Classification Engine REST endpoints
     3→ *
     4→ * These types match the OpenAPI specification and are used by contract tests.
     5→ * They bridge between the Gmail API payload format and our internal types.
     6→ */
     7→
     8→import { ClassificationResult, ExplainabilityTrace, ScoreBreakdown, AttributeContext } from './index';
     9→
    10→/**
    11→ * EmailContent - Simplified version of EmailMessage for API requests
    12→ * Maps to EmailMessage but with optional fields for API flexibility
    13→ */
    14→export interface EmailContent {
    15→  id: string;
    16→  threadId: string;
    17→  subject: string;
    18→  from: {
    19→    email: string;
    20→    name?: string;
    21→    raw: string;
    22→  };
    23→  to: Array<{
    24→    email: string;
    25→    name?: string;
    26→    raw: string;
    27→  }>;
    28→  cc?: Array<{
    29→    email: string;
    30→    name?: string;
    31→    raw: string;
    32→  }>;
    33→  bcc?: Array<{
    34→    email: string;
    35→    name?: string;
    36→    raw: string;
    37→  }>;
    38→  date: Date;
    39→  bodyPlain?: string;
    40→  bodyHtml?: string;
    41→  headers: Array<{
    42→    name: string;
    43→    value: string;
    44→  }>;
    45→
    46→  // Gmail API specific fields
    47→  snippet?: string;
    48→  historyId?: string;
    49→  sizeEstimate?: number;
    50→}
    51→
    52→/**
    53→ * Request for batch classification endpoint
    54→ */
    55→export interface BatchClassificationRequest {
    56→  emails: EmailContent[];
    57→  sessionId: string;
    58→  processingMode?: 'parallel' | 'sequential';
    59→  configVersion?: string;
    60→}
    61→
    62→/**
    63→ * Response from batch classification endpoint
    64→ */
    65→export interface BatchClassificationResponse {
    66→  sessionId: string;
    67→  processedCount: number;
    68→  successCount: number;
    69→  errorCount: number;
    70→  results: BatchClassificationResult[];
    71→  performanceMetrics: {
    72→    totalDurationMs: number;
    73→    avgEmailDurationMs: number;
    74→    parallelStagesCount: number;
    75→    databaseBatchOps: number;
    76→  };
    77→  configVersion: string;
    78→  errors?: ClassificationError[];
    79→}
