/**
 * API types for Classification Engine REST endpoints
 *
 * These types match the OpenAPI specification and are used by contract tests.
 * They bridge between the Gmail API payload format and our internal types.
 */

import { ClassificationResult, ExplainabilityTrace, ScoreBreakdown, AttributeContext } from './index';

/**
 * EmailContent - Simplified version of EmailMessage for API requests
 * Maps to EmailMessage but with optional fields for API flexibility
 */
export interface EmailContent {
  id: string;
  threadId: string;
  subject: string;
  from: {
    email: string;
    name?: string;
    raw: string;
  };
  to: Array<{
    email: string;
    name?: string;
    raw: string;
  }>;
  cc?: Array<{
    email: string;
    name?: string;
    raw: string;
  }>;
  bcc?: Array<{
    email: string;
    name?: string;
    raw: string;
  }>;
  date: Date;
  bodyPlain?: string;
  bodyHtml?: string;
  headers: Array<{
    name: string;
    value: string;
  }>;

  // Gmail API specific fields
  snippet?: string;
  historyId?: string;
  sizeEstimate?: number;
}

/**
 * Request for batch classification endpoint
 */
export interface BatchClassificationRequest {
  emails: EmailContent[];
  sessionId: string;
  processingMode?: 'parallel' | 'sequential';
  configVersion?: string;
}

/**
 * Response from batch classification endpoint
 */
export interface BatchClassificationResponse {
  sessionId: string;
  processedCount: number;
  successCount: number;
  errorCount: number;
  results: BatchClassificationResult[];
  performanceMetrics: {
    totalDurationMs: number;
    avgEmailDurationMs: number;
    parallelStagesCount: number;
    databaseBatchOps: number;
  };
  configVersion: string;
  errors?: ClassificationError[];
}

/**
 * Individual classification result in batch response
 */
export interface BatchClassificationResult {
  emailId: string;
  classification: ClassificationResult;
  explainabilityTrace?: ExplainabilityTrace;
  processingDurationMs: number;
  success: boolean;
  error?: string;

  // Direct access properties for easier testing
  primaryCategory: string;
  secondaryCategories: string[]; // Secondary category labels
  subtype: string | null; // Primary subtype (from classification.subtype)
  confidence: number;
  scoreBreakdown: ScoreBreakdown;
  attributeContext: AttributeContext;
}

