/**
 * Rule Compiler
 *
 * Compiles configuration rules into optimized RegExp patterns for performance.
 * Uses the Strategy Pattern to handle different rule operations cleanly.
 *
 * ## Adding New Operations
 *
 * To add a new rule operation:
 * 1. Create a class implementing RuleOperationStrategy
 * 2. Add it to the operationStrategies map in RuleCompiler constructor
 * 3. The new operation is automatically supported without modifying core logic
 *
 * Example:
 * ```typescript
 * class ExactMatchStrategy implements RuleOperationStrategy {
 *   compile(ruleContext: RuleContext): CompiledRule {
 *     // Implementation here
 *   }
 * }
 * ```
 */

import { CategoryConfiguration } from '../types/category-configuration';
import { logger } from '../utils/logger';
import { CompiledRule } from '../types/api-types';

/**
 * Context information passed to rule operation strategies
 */
interface RuleContext {
  id: string;
  category: string;
  subtype: string;
  tier: 'high' | 'medium' | 'low';
  field: string;
  operation: string;
  values: string[];
  weight: number;
}

/**
 * Strategy interface for compiling different rule operations
 *
 * Each operation (containsAny, notContains, regexAny, etc.) has its own
 * strategy implementation that knows how to compile rules for that operation.
 */
interface RuleOperationStrategy {
  /**
   * Compile a rule into an optimized CompiledRule
   *
   * @param context - Rule context with all necessary information
   * @returns Compiled rule ready for runtime evaluation
   */
  compile(context: RuleContext): CompiledRule;
}

/**
 * Utility function to escape special regex characters for literal matching
 */
function escapeRegex(str: string): string {
  return str.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

/**
 * Strategy for containsAny operation
 * Compiles to a RegExp that matches if any of the values are found (case-insensitive)
 */
class ContainsAnyStrategy implements RuleOperationStrategy {
  compile(context: RuleContext): CompiledRule {
    if (context.values.length === 0) {
      throw new Error('ContainsAny requires at least one value');
    }

    // Escape special regex characters and join with OR
    const pattern = new RegExp(context.values.map((v) => escapeRegex(v)).join('|'), 'i');

    return {
      id: context.id,
      category: context.category,
      subtype: context.subtype,
      pattern,
      weight: context.weight,
      tier: context.tier,
    };
  }
}

/**
 * Strategy for startsWith operation
 * Compiles to a RegExp anchored at the start of the string
 */
class StartsWithStrategy implements RuleOperationStrategy {
  compile(context: RuleContext): CompiledRule {
    if (context.values.length === 0) {
      throw new Error('StartsWith requires at least one value');
    }

    // Anchor at start and escape special characters
    const pattern = new RegExp('^(' + context.values.map((v) => escapeRegex(v)).join('|') + ')', 'i');

    return {
      id: context.id,
      category: context.category,
      subtype: context.subtype,
      pattern,
      weight: context.weight,
      tier: context.tier,
    };
  }
}

/**
 * Strategy for endsWith operation
 * Compiles to a RegExp anchored at the end of the string
 */
class EndsWithStrategy implements RuleOperationStrategy {
  compile(context: RuleContext): CompiledRule {
    if (context.values.length === 0) {
      throw new Error('EndsWith requires at least one value');
    }

    // Anchor at end and escape special characters
    const pattern = new RegExp('(' + context.values.map((v) => escapeRegex(v)).join('|') + ')$', 'i');

    return {
      id: context.id,
      category: context.category,
      subtype: context.subtype,
      pattern,
      weight: context.weight,
      tier: context.tier,
    };
  }
}

/**
 * Strategy for regexAny operation
 * Uses raw regex patterns (no escaping) - assumes patterns are valid regex
 */
class RegexAnyStrategy implements RuleOperationStrategy {
  compile(context: RuleContext): CompiledRule {
    if (context.values.length === 0) {
      throw new Error('RegexAny requires at least one pattern');
    }

    // Join raw regex patterns (assumes they're already valid)
    const pattern = new RegExp(context.values.join('|'), 'i');

    return {
      id: context.id,
      category: context.category,
      subtype: context.subtype,
      pattern,
      weight: context.weight,
      tier: context.tier,
    };
  }
}

/**
 * Strategy for notContains operation
 * Does NOT compile to RegExp - stores values for runtime evaluation
 *
 * Rationale: We can't negate a pattern match efficiently with regex,
 * so we defer to runtime evaluation where we can check !contains(value)
 */
class NotContainsStrategy implements RuleOperationStrategy {
  compile(context: RuleContext): CompiledRule {
    // No RegExp compilation for negative operations
    // Store values and operation for runtime evaluation
    return {
      id: context.id,
      category: context.category,
      subtype: context.subtype,
      pattern: null, // No RegExp for negative operations
      weight: context.weight,
      tier: context.tier,
      operation: context.operation,
      values: context.values,
      field: context.field,
    };
  }
}

/**
 * RuleCompiler - Compiles configuration rules for runtime optimization
 *
 * Uses the Strategy Pattern to delegate compilation to operation-specific strategies.
 * This design follows the Open/Closed Principle: open for extension (add new strategies)
 * but closed for modification (no need to touch core compilation logic).
 */
export class RuleCompiler {
  private readonly operationStrategies: Map<string, RuleOperationStrategy>;

  constructor() {
    // Register all supported operation strategies
    this.operationStrategies = new Map([
      ['containsAny', new ContainsAnyStrategy()],
      ['startsWith', new StartsWithStrategy()],
      ['endsWith', new EndsWithStrategy()],
      ['regexAny', new RegexAnyStrategy()],
      ['notContains', new NotContainsStrategy()],
    ]);
  }
  /**
   * Compile configuration rules into optimized patterns
   *
   * Uses the Strategy Pattern to delegate compilation to operation-specific handlers.
   * Each operation (containsAny, notContains, etc.) has its own strategy that knows
   * how to compile rules for that operation.
   *
   * @param config - Category configuration with rule definitions
   * @returns Array of compiled rules with RegExp patterns
   */
  compileRules(config: CategoryConfiguration): CompiledRule[] {
    const rules: CompiledRule[] = [];

    for (const [categoryName, category] of Object.entries(config.processingConfig.topLevelCategories)) {
      for (const [subtypeName, subtype] of Object.entries(category.subtypes)) {
        if (subtype.ruleBasedClassification) {
          for (const [tier, ruleList] of Object.entries(subtype.ruleBasedClassification)) {
            if (ruleList) {
              // Normalize tier names: "highConfidence" → "high", "mediumConfidence" → "medium", "lowConfidence" → "low"
              const normalizedTier = this.normalizeTierName(tier);

              for (let ruleIndex = 0; ruleIndex < ruleList.length; ruleIndex++) {
                const rule = ruleList[ruleIndex];
                try {
                  // Look up the strategy for this operation
                  const strategy = this.operationStrategies.get(rule.operation);

                  if (!strategy) {
                    logger.warn(
                      { category: categoryName, subtype: subtypeName, tier, ruleIndex, operation: rule.operation },
                      'Unsupported rule operation - skipping'
                    );
                    continue;
                  }

                  // Build rule context
                  const context: RuleContext = {
                    id: `${categoryName}.${subtypeName}.${tier}.${ruleIndex}`,
                    category: categoryName,
                    subtype: subtypeName,
                    tier: normalizedTier,
                    field: rule.field,
                    operation: rule.operation,
                    values: rule.values || [],
                    weight: rule.weight,
                  };

                  // Delegate compilation to the strategy
                  const compiledRule = strategy.compile(context);
                  rules.push(compiledRule);
                } catch (error) {
                  // Skip invalid regex patterns or other compilation errors
                  logger.warn(
                    { category: categoryName, subtype: subtypeName, tier, ruleIndex, error },
                    'Failed to compile rule'
                  );
                }
              }
            }
          }
        }
      }
    }

    return rules;
  }

  /**
   * Normalize tier names from config format to API format
   *
   * @param tier - Tier name from config ("highConfidence", "mediumConfidence", "lowConfidence")
   * @returns Normalized tier name ("high", "medium", "low")
   */
  private normalizeTierName(tier: string): 'high' | 'medium' | 'low' {
    // Handle both formats: "highConfidence" and "high"
    if (tier === 'highConfidence' || tier === 'high') return 'high';
    if (tier === 'mediumConfidence' || tier === 'medium') return 'medium';
    if (tier === 'lowConfidence' || tier === 'low') return 'low';

    // Default to low for unknown tiers
    logger.warn({ tier }, "Unknown tier name - defaulting to 'low'");
    return 'low';
  }
}

// Default compiler instance
export const ruleCompiler = new RuleCompiler();

