      expect(compiled).toHaveLength(0);
    });
  });

  describe('Operation Validation', () => {
    it('validates supported operations', () => {
      expect(compiler.validateOperation('containsAny')).toBe(true);
      expect(compiler.validateOperation('startsWith')).toBe(true);
      expect(compiler.validateOperation('endsWith')).toBe(true);
      expect(compiler.validateOperation('regexAny')).toBe(true);
      expect(compiler.validateOperation('notContains')).toBe(true);
    });

    it('rejects unsupported operations', () => {
      expect(compiler.validateOperation('unknownOp')).toBe(false);
      expect(compiler.validateOperation('exactMatch')).toBe(false);
      expect(compiler.validateOperation('')).toBe(false);
    });

    it('returns list of all supported operations', () => {
      const supported = compiler.getSupportedOperations();
      expect(supported).toHaveLength(5);
      expect(supported).toContain('containsAny');
      expect(supported).toContain('startsWith');
      expect(supported).toContain('endsWith');
      expect(supported).toContain('regexAny');
      expect(supported).toContain('notContains');
    });

    it('provides useful info for config validation errors', () => {
      const supported = compiler.getSupportedOperations();
      const errorMessage = `Unsupported operation. Supported operations are: ${supported.join(', ')}`;

      expect(errorMessage).toContain('containsAny');
      expect(errorMessage).toContain('notContains');
      expect(errorMessage).toContain('regexAny');
    });
  });
});

