/**
 * Type definitions for rule operation strategies
 */

import { CompiledRule } from '../../types/api-types';

/**
 * Context information passed to rule operation strategies
 */
export interface RuleContext {
  id: string;
  category: string;
  subtype: string;
  tier: 'high' | 'medium' | 'low';
  field: string;
  operation: string;
  values: string[];
  weight: number;
}

/**
 * Strategy interface for compiling different rule operations
 *
 * Each operation (containsAny, notContains, regexAny, etc.) has its own
 * strategy implementation that knows how to compile rules for that operation.
 */
export interface RuleOperationStrategy {
  /**
   * Compile a rule into an optimized CompiledRule
   *
   * @param context - Rule context with all necessary information
   * @returns Compiled rule ready for runtime evaluation
   */
  compile(context: RuleContext): CompiledRule;
}

/**
 * Utility functions for rule operation compilation
 */

/**
 * Escape special regex characters for literal matching
 *
 * Used by strategies that compile literal text patterns (containsAny, startsWith, endsWith)
 * to ensure special regex characters like $, ., *, etc. are matched literally.
 *
 * @param str - String to escape
 * @returns String with special regex characters escaped
 */
export function escapeRegex(str: string): string {
  return str.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

/**
 * ContainsAny operation strategy
 *
 * Compiles to a RegExp that matches if any of the values are found (case-insensitive)
 */

import { CompiledRule } from '../../types/api-types';
import { RuleContext, RuleOperationStrategy } from './types';
import { escapeRegex } from './utils';

export class ContainsAnyStrategy implements RuleOperationStrategy {
  compile(context: RuleContext): CompiledRule {
    if (context.values.length === 0) {
      throw new Error('ContainsAny requires at least one value');
    }

    // Escape special regex characters and join with OR
    const pattern = new RegExp(context.values.map((v) => escapeRegex(v)).join('|'), 'i');

    return {
      id: context.id,
      category: context.category,
      subtype: context.subtype,
      pattern,
      weight: context.weight,
      tier: context.tier,
    };
  }
}

/**
 * StartsWith operation strategy
 *
 * Compiles to a RegExp anchored at the start of the string
 */

import { CompiledRule } from '../../types/api-types';
import { RuleContext, RuleOperationStrategy } from './types';
import { escapeRegex } from './utils';

export class StartsWithStrategy implements RuleOperationStrategy {
  compile(context: RuleContext): CompiledRule {
    if (context.values.length === 0) {
      throw new Error('StartsWith requires at least one value');
    }

    // Anchor at start and escape special characters
    const pattern = new RegExp('^(' + context.values.map((v) => escapeRegex(v)).join('|') + ')', 'i');

    return {
      id: context.id,
      category: context.category,
      subtype: context.subtype,
      pattern,
      weight: context.weight,
      tier: context.tier,
    };
  }
}

/**
 * EndsWith operation strategy
 *
 * Compiles to a RegExp anchored at the end of the string
 */

import { CompiledRule } from '../../types/api-types';
import { RuleContext, RuleOperationStrategy } from './types';
import { escapeRegex } from './utils';

export class EndsWithStrategy implements RuleOperationStrategy {
  compile(context: RuleContext): CompiledRule {
    if (context.values.length === 0) {
      throw new Error('EndsWith requires at least one value');
    }

    // Anchor at end and escape special characters
    const pattern = new RegExp('(' + context.values.map((v) => escapeRegex(v)).join('|') + ')$', 'i');

    return {
      id: context.id,
      category: context.category,
      subtype: context.subtype,
      pattern,
      weight: context.weight,
      tier: context.tier,
    };
  }
}

/**
 * RegexAny operation strategy
 *
 * Uses raw regex patterns (no escaping) - assumes patterns are valid regex
 */

import { CompiledRule } from '../../types/api-types';
import { RuleContext, RuleOperationStrategy } from './types';

export class RegexAnyStrategy implements RuleOperationStrategy {
  compile(context: RuleContext): CompiledRule {
    if (context.values.length === 0) {
      throw new Error('RegexAny requires at least one pattern');
    }

    // Join raw regex patterns (assumes they're already valid)
    const pattern = new RegExp(context.values.join('|'), 'i');

    return {
      id: context.id,
      category: context.category,
      subtype: context.subtype,
      pattern,
      weight: context.weight,
      tier: context.tier,
    };
  }
}

/**
 * NotContains operation strategy
 *
 * Does NOT compile to RegExp - stores values for runtime evaluation
 *
 * Rationale: We can't negate a pattern match efficiently with regex,
 * so we defer to runtime evaluation where we can check !contains(value)
 */

import { CompiledRule } from '../../types/api-types';
import { RuleContext, RuleOperationStrategy } from './types';

export class NotContainsStrategy implements RuleOperationStrategy {
  compile(context: RuleContext): CompiledRule {
    // No RegExp compilation for negative operations
    // Store values and operation for runtime evaluation
    return {
      id: context.id,
      category: context.category,
      subtype: context.subtype,
      pattern: null, // No RegExp for negative operations
      weight: context.weight,
      tier: context.tier,
      operation: context.operation,
      values: context.values,
      field: context.field,
    };
  }
}

/**
 * Rule operation strategies
 *
 * Barrel export for clean imports. Each operation has its own file following
 * the Single Responsibility Principle.
 */

export { RuleContext, RuleOperationStrategy } from './types';
export { escapeRegex } from './utils';
export { ContainsAnyStrategy } from './contains-any-strategy';
export { StartsWithStrategy } from './starts-with-strategy';
export { EndsWithStrategy } from './ends-with-strategy';
export { RegexAnyStrategy } from './regex-any-strategy';
export { NotContainsStrategy } from './not-contains-strategy';

