import { RuleCompiler } from '../../../src/config/rule-compiler';
import {
  createTestCategoryConfig,
  validMinimalCategoryConfig,
} from '../../fixtures/configs/valid-minimal-category-config';

describe('RuleCompiler', () => {
  const compiler = new RuleCompiler();

  it('compiles literal rule operations into case-insensitive regular expressions', () => {
    const baseProcessing = validMinimalCategoryConfig.processingConfig;
    const configWithRules = createTestCategoryConfig({
      processingConfig: {
        ...baseProcessing,
        topLevelCategories: {
          financial: {
            description: 'Financial communications',
            subtypes: {
              receipt: {
                description: 'Receipts',
                derived: false,
                parallelSafe: true,
                ruleBasedClassification: {
                  highConfidence: [
                    {
                      field: 'subject',
                      operation: 'containsAny',
                      values: ['Receipt #', 'Invoice (Final)'],
                      weight: 1,
                    },
                    {
                      field: 'subject',
                      operation: 'startsWith',
                      values: ['Payment confirmation'],
                      weight: 0.8,
                    },
                    {
                      field: 'subject',
                      operation: 'endsWith',
                      values: ['statement.pdf'],
                      weight: 0.6,
                    },
                  ],
                  mediumConfidence: [
                    {
                      field: 'body',
                      operation: 'regexAny',
                      values: ['total\\s+\\$\\d+\\.\\d{2}'],
                      weight: 0.5,
                    },
                  ],
                },
              },
            },
            aiFinalClassification: {
              categoryDescription: 'Financial classification',
              decisionCriteria: ['Contains transaction details'],
            },
          },
        },
      },
    });

    const compiled = compiler.compileRules(configWithRules);

    expect(compiled).toHaveLength(4);
    const ids = compiled.map((rule) => rule.id);
    expect(ids).toContain('financial.receipt.highConfidence.0');
    expect(ids).toContain('financial.receipt.highConfidence.1');
    expect(ids).toContain('financial.receipt.highConfidence.2');
    expect(ids).toContain('financial.receipt.mediumConfidence.0');

    const containsAnyRule = compiled.find((rule) => rule.id.endsWith('0'));
    expect(containsAnyRule).toBeDefined();
    if (containsAnyRule && containsAnyRule.pattern) {
      expect(containsAnyRule.pattern.test('Your Receipt #12345 is ready')).toBe(true);
      expect(containsAnyRule.pattern.test('Invoice (Final) available')).toBe(true);
      expect(containsAnyRule.pattern.test('Invoice [Draft]')).toBe(false);
    }
  });

  it('skips invalid regex patterns without throwing', () => {
    const baseProcessing = validMinimalCategoryConfig.processingConfig;
    const configWithInvalidRegex = createTestCategoryConfig({
      processingConfig: {
        ...baseProcessing,
        topLevelCategories: {
          alerts: {
            description: 'Alert notifications',
            subtypes: {
              generic: {
                description: 'Generic alert',
                derived: false,
                parallelSafe: true,
                ruleBasedClassification: {
                  highConfidence: [
                    {
                      field: 'subject',
                      operation: 'regexAny',
                      values: ['(*invalid'],
                      weight: 1,
                    },
                  ],
                },
              },
            },
            aiFinalClassification: {
              categoryDescription: 'Alert notifications',
              decisionCriteria: ['Contains alert keywords'],
            },
          },
        },
      },
    });

    expect(() => compiler.compileRules(configWithInvalidRegex)).not.toThrow();
    const compiled = compiler.compileRules(configWithInvalidRegex);
    expect(compiled).toHaveLength(0);
  });

  it('compiles notContains rules for exclusion patterns', () => {
    const baseProcessing = validMinimalCategoryConfig.processingConfig;
    const configWithNotContains = createTestCategoryConfig({
      processingConfig: {
        ...baseProcessing,
        topLevelCategories: {
          subscriptionContent: {
            description: 'Subscription content',
            subtypes: {
              newsletter: {
                description: 'Newsletters',
                derived: false,
                parallelSafe: true,
                ruleBasedClassification: {
                  highConfidence: [
                    {
                      field: 'subject',
                      operation: 'notContains',
                      values: ['unsubscribe', 'spam', 'advertisement'],
                      weight: 0.5,
                    },
                  ],
                },
              },
            },
            aiFinalClassification: {
              categoryDescription: 'Subscription content',
              decisionCriteria: ['Newsletter-like content'],
            },
          },
        },
      },
    });

    const compiled = compiler.compileRules(configWithNotContains);
    expect(compiled).toHaveLength(1);
    expect(compiled[0].id).toBe('subscriptionContent.newsletter.highConfidence.0');
  });

  describe('Operation Strategy Pattern', () => {
    describe('ContainsAnyStrategy', () => {
      it('compiles containsAny rules with case-insensitive matching', () => {
        const baseProcessing = validMinimalCategoryConfig.processingConfig;
        const config = createTestCategoryConfig({
          processingConfig: {
            ...baseProcessing,
            topLevelCategories: {
              test: {
                description: 'Test category',
                subtypes: {
                  basic: {
                    description: 'Basic test',
                    derived: false,
                    parallelSafe: true,
                    ruleBasedClassification: {
                      highConfidence: [
                        {
                          field: 'subject',
                          operation: 'containsAny',
                          values: ['Receipt', 'Invoice'],
                          weight: 1.0,
                        },
                      ],
                    },
                  },
                },
                aiFinalClassification: {
                  categoryDescription: 'Test',
                  decisionCriteria: ['Test criteria'],
                },
              },
            },
          },
        });

        const compiled = compiler.compileRules(config);
        expect(compiled).toHaveLength(1);
        expect(compiled[0].pattern).toBeDefined();
        expect(compiled[0].pattern?.test('Your receipt is ready')).toBe(true);
        expect(compiled[0].pattern?.test('Invoice available')).toBe(true);
        expect(compiled[0].pattern?.test('Payment processed')).toBe(false);
      });

      it('escapes special regex characters in containsAny values', () => {
        const baseProcessing = validMinimalCategoryConfig.processingConfig;
        const config = createTestCategoryConfig({
          processingConfig: {
            ...baseProcessing,
            topLevelCategories: {
              test: {
                description: 'Test category',
                subtypes: {
                  basic: {
                    description: 'Basic test',
                    derived: false,
                    parallelSafe: true,
                    ruleBasedClassification: {
                      highConfidence: [
                        {
                          field: 'subject',
                          operation: 'containsAny',
                          values: ['$100.00', 'Price: $50'],
                          weight: 1.0,
                        },
                      ],
                    },
                  },
                },
                aiFinalClassification: {
                  categoryDescription: 'Test',
                  decisionCriteria: ['Test criteria'],
                },
              },
            },
          },
        });

        const compiled = compiler.compileRules(config);
        expect(compiled).toHaveLength(1);
        expect(compiled[0].pattern?.test('Total: $100.00')).toBe(true);
        expect(compiled[0].pattern?.test('Price: $50')).toBe(true);
        // Should NOT match if not escaped ($ is regex special char)
        expect(compiled[0].pattern?.test('X100X00')).toBe(false);
      });
    });

    describe('StartsWithStrategy', () => {
      it('compiles startsWith rules with anchor at beginning', () => {
        const baseProcessing = validMinimalCategoryConfig.processingConfig;
        const config = createTestCategoryConfig({
          processingConfig: {
            ...baseProcessing,
            topLevelCategories: {
              test: {
                description: 'Test category',
                subtypes: {
                  basic: {
                    description: 'Basic test',
                    derived: false,
                    parallelSafe: true,
                    ruleBasedClassification: {
                      highConfidence: [
                        {
                          field: 'subject',
                          operation: 'startsWith',
                          values: ['RE:', 'FWD:'],
                          weight: 1.0,
                        },
                      ],
                    },
                  },
                },
                aiFinalClassification: {
                  categoryDescription: 'Test',
                  decisionCriteria: ['Test criteria'],
                },
              },
            },
          },
        });

        const compiled = compiler.compileRules(config);
        expect(compiled).toHaveLength(1);
        expect(compiled[0].pattern?.test('RE: Your email')).toBe(true);
        expect(compiled[0].pattern?.test('FWD: Important')).toBe(true);
        expect(compiled[0].pattern?.test('Check this RE: stuff')).toBe(false);
      });
    });

    describe('EndsWithStrategy', () => {
      it('compiles endsWith rules with anchor at end', () => {
        const baseProcessing = validMinimalCategoryConfig.processingConfig;
        const config = createTestCategoryConfig({
          processingConfig: {
            ...baseProcessing,
            topLevelCategories: {
              test: {
                description: 'Test category',
                subtypes: {
                  basic: {
                    description: 'Basic test',
                    derived: false,
                    parallelSafe: true,
                    ruleBasedClassification: {
                      highConfidence: [
                        {
                          field: 'subject',
                          operation: 'endsWith',
                          values: ['.pdf', '.docx'],
                          weight: 1.0,
                        },
                      ],
                    },
                  },
                },
                aiFinalClassification: {
                  categoryDescription: 'Test',
                  decisionCriteria: ['Test criteria'],
                },
              },
            },
          },
        });

        const compiled = compiler.compileRules(config);
        expect(compiled).toHaveLength(1);
        expect(compiled[0].pattern?.test('document.pdf')).toBe(true);
        expect(compiled[0].pattern?.test('report.docx')).toBe(true);
        expect(compiled[0].pattern?.test('file.pdf.backup')).toBe(false);
      });
    });

    describe('RegexAnyStrategy', () => {
      it('compiles regexAny rules with raw regex patterns', () => {
        const baseProcessing = validMinimalCategoryConfig.processingConfig;
        const config = createTestCategoryConfig({
          processingConfig: {
            ...baseProcessing,
            topLevelCategories: {
              test: {
                description: 'Test category',
                subtypes: {
                  basic: {
                    description: 'Basic test',
                    derived: false,
                    parallelSafe: true,
                    ruleBasedClassification: {
                      highConfidence: [
                        {
                          field: 'body',
                          operation: 'regexAny',
                          values: ['\\$\\d+\\.\\d{2}', 'total.*amount'],
                          weight: 1.0,
                        },
                      ],
                    },
                  },
                },
                aiFinalClassification: {
                  categoryDescription: 'Test',
                  decisionCriteria: ['Test criteria'],
                },
              },
            },
          },
        });

        const compiled = compiler.compileRules(config);
        expect(compiled).toHaveLength(1);
        expect(compiled[0].pattern?.test('Price: $99.99')).toBe(true);
        expect(compiled[0].pattern?.test('Total due amount: $50')).toBe(true);
        expect(compiled[0].pattern?.test('No match here')).toBe(false);
      });
    });

    describe('NotContainsStrategy', () => {
      it('compiles notContains rules without RegExp pattern', () => {
        const baseProcessing = validMinimalCategoryConfig.processingConfig;
        const config = createTestCategoryConfig({
          processingConfig: {
            ...baseProcessing,
            topLevelCategories: {
              test: {
                description: 'Test category',
                subtypes: {
                  basic: {
                    description: 'Basic test',
                    derived: false,
                    parallelSafe: true,
                    ruleBasedClassification: {
                      highConfidence: [
                        {
                          field: 'subject',
                          operation: 'notContains',
                          values: ['spam', 'unsubscribe'],
                          weight: 0.5,
                        },
                      ],
                    },
                  },
                },
                aiFinalClassification: {
                  categoryDescription: 'Test',
                  decisionCriteria: ['Test criteria'],
                },
              },
            },
          },
        });

        const compiled = compiler.compileRules(config);
        expect(compiled).toHaveLength(1);
        expect(compiled[0].pattern).toBeNull();
        expect(compiled[0].operation).toBe('notContains');
        expect(compiled[0].values).toEqual(['spam', 'unsubscribe']);
        expect(compiled[0].field).toBe('subject');
      });
    });

    it('handles unsupported operations gracefully', () => {
      const baseProcessing = validMinimalCategoryConfig.processingConfig;
      const config = createTestCategoryConfig({
        processingConfig: {
          ...baseProcessing,
          topLevelCategories: {
            test: {
              description: 'Test category',
              subtypes: {
                basic: {
                  description: 'Basic test',
                  derived: false,
                  parallelSafe: true,
                  ruleBasedClassification: {
                    highConfidence: [
                      {
                        field: 'subject',
                        // eslint-disable-next-line @typescript-eslint/no-explicit-any
